export type ContractAddressMap = Record<number, Record<string, `0x${string}`>>;

/**
 * Generated by scripts/write-contract-artifact.mjs
 *
 * Shape:
 * {
 *   [chainId]: {
 *     [contractName]: address
 *   }
 * }
 *
 * Populated by: pnpm deploy          (local)
 *               pnpm deploy:testnet  (testnet)
 *               pnpm deploy:mainnet  (mainnet)
 */
export const CONTRACT_ADDRESSES_BY_CHAIN_ID: ContractAddressMap = {} as ContractAddressMap;

export function getContractAddress(chainId: number, contractName: string): `0x${string}` | undefined {
  return CONTRACT_ADDRESSES_BY_CHAIN_ID[chainId]?.[contractName];
}
